import numpy as npimport mathdef measure_physical_arm(x_signal, y_signal, dt=0.001):    """    Simulates a single Arm-Chain oscillator.    Instead of calculating the EML formula directly, this generates a     physical wave, measures it, and derives the output organically.    """    # Time vector    t = np.arange(0, 1.0, dt)        # The Biological/Physical Mapping:    # Input X drives the amplitude    # Input Y drives the natural frequency    amplitude = np.exp(x_signal)    frequency = np.log(y_signal)        # Generate the continuous physical wave: Z(t) = A * e^(i * w * t)    wave = amplitude * np.exp(1j * frequency * t)        # ===============================================================    # THE MEASUREMENT (No EML math formulas here)    # The AIS reads the physical properties of the continuous wave    # ===============================================================        # 1. Extract physical amplitude    measured_amp = np.mean(np.abs(wave))        # 2. Extract physical frequency (phase derivative)    phases = np.unwrap(np.angle(wave))    measured_freq = np.mean(np.diff(phases) / dt)        # The node's output is the interference: Amplitude minus Frequency    node_output = measured_amp - measured_freq        return node_outputdef execute_eml_ln_circuit(z):    """    Executes Odrzywolek's binary tree for ln(z) using physical waves.    Target: ln(z) = eml(1, eml(eml(1, z), 1))    """    # Node 1: Input (1, z)    node1_out = measure_physical_arm(1.0, z)        # Node 2: Input (Node 1 Output, 1)    node2_out = measure_physical_arm(node1_out, 1.0)        # Node 3: Input (1, Node 2 Output)    node3_out = measure_physical_arm(1.0, node2_out)        return node3_outif __name__ == "__main__":    print("="*75)    print(" EXECUTING EML BINARY TREE ON CONTINUOUS WAVE OSCILLATORS")    print(" Target Circuit: ln(z) = eml(1, eml(eml(1, z), 1))")    print("="*75)    print(f"{'Input (z)':<12} | {'Wave Circuit Output':<22} | {'Theory: math.log(z)':<22} | {'Error'}")    print("-" * 75)        # Test a range of inputs    test_values = [2.0, 3.0, 5.0, 7.0, 10.0, 15.0, 42.0]        for z in test_values:        # Run the physical wave circuit        circuit_output = execute_eml_ln_circuit(z)                # The theoretical target        theory = math.log(z)                # Calculate error        error = abs(circuit_output - theory)                print(f"{z:<12.1f} | {circuit_output:<22.15f} | {theory:<22.15f} | {error:.2e}")